                    "/generated/" in path || "/gen/" in path || "/build/" in path || "/out/" in path -> SourceCategory.GENERATED
                    "/resources/" in path -> SourceCategory.RESOURCES
                    else -> SourceCategory.OTHER
                }
            }
            else -> SourceCategory.SOURCE
