    private fun classifyLine(
        text: String,
        lineStart: Int,
        lineEnd: Int,
        inBlockIn: Boolean,
        style: CommentStyle,
    ): Pair<Boolean, Boolean> {
        var hasCode = false
        var inBlock = inBlockIn
        var j = lineStart
